import okhttp3.Interceptor
import okhttp3.OkHttpClient
import retrofit2.Retrofit
import retrofit2.converter.gson.GsonConverterFactory
import retrofit2.http.GET
import java.util.concurrent.TimeUnit

// Define the API interface
interface ApiService {
    @GET("users")
    suspend fun fetchUsers(): List<User>
}

// Data class for User
data class User(val id: Int, val name: String)

// Interceptor to add authentication token
class AuthInterceptor(private val authToken: String) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): okhttp3.Response {
        val request = chain.request().newBuilder()
            .header("Authorization", "Bearer $authToken")
            .build()
        return chain.proceed(request)
    }
}

// Network module class
object NetworkModule {

    private const val BASE_URL_DEV = "https://api.example.com/"
    private const val BASE_URL_STAGING = "https://staging.api.example.com/"
    private const val BASE_URL_PRODUCTION = "https://production.api.example.com/"

    fun provideApiService(environment: String, authToken: String): ApiService {
        val okHttpClient = OkHttpClient.Builder()
            .addInterceptor(AuthInterceptor(authToken))
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .build()

        val retrofit = Retrofit.Builder()
            .baseUrl(getBaseUrl(environment))
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()

        return retrofit.create(ApiService::class.java)
    }

    private fun getBaseUrl(environment: String): String {
        return when (environment) {
            "dev" -> BASE_URL_DEV
            "staging" -> BASE_URL_STAGING
            else -> BASE_URL_PRODUCTION
        }
    }
}